const canvas = document.getElementById("bg-canvas");
const scene = new THREE.Scene();
const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
const renderer = new THREE.WebGLRenderer({
	canvas: canvas,
	alpha: true
});

const uniforms = {
	uTime: { value: 0 },
	uColor: { value: new THREE.Color(0x090909) },
	uResolution: { value: new THREE.Vector2() },
	uMouse: { value: new THREE.Vector2(0.5, 0.5) },
	uIntensity: { value: 0.0 },
	uMode: { value: 0 }
};

const material = new THREE.ShaderMaterial({
	uniforms: uniforms,
	vertexShader: `
        varying vec2 vUv;
        void main() {
            vUv = uv;
            gl_Position = vec4(position, 1.0);
        }
    `,
	fragmentShader: `
        uniform float uTime;
        uniform vec3 uColor;
        uniform vec2 uResolution;
        uniform vec2 uMouse;
        uniform float uIntensity; 
        uniform int uMode; 
        varying vec2 vUv;

        float random(vec2 st) { return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123); }

        float noise(vec2 st) {
            vec2 i = floor(st); vec2 f = fract(st);
            float a = random(i); float b = random(i + vec2(1.0, 0.0));
            float c = random(i + vec2(0.0, 1.0)); float d = random(i + vec2(1.0, 1.0));
            vec2 u = f * f * (3.0 - 2.0 * f);
            return mix(a, b, u.x) + (c - a)* u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
        }

        float fbm(vec2 st) {
            float value = 0.0; float amp = .5;
            for (int i = 0; i < 5; i++) { value += amp * noise(st); st *= 2.; amp *= .5; }
            return value;
        }

        float grid(vec2 st, float res) {
            vec2 grid = fract(st * res);
            return (step(0.98, grid.x*1.03) + step(0.98, grid.y*1.03));
        }

        void main() {
            vec2 st = gl_FragCoord.xy / uResolution.xy;
            float aspect = uResolution.x / uResolution.y;
            st.x *= aspect;

            vec2 mousePos = uMouse;
            mousePos.x *= aspect; 
            vec2 toMouse = st - mousePos;
            float distMouse = length(toMouse);
            float mouseInteraction = smoothstep(0.4, 0.0, distMouse);

            vec3 finalColor = vec3(0.0);
            vec2 warpSt = st; 

            if (uMode == 0) {
                warpSt -= toMouse * mouseInteraction * 0.05;
                warpSt.x += sin(st.y * 5.0 + uTime * 0.2) * 0.01;
            }
            else if (uMode == 1) { 
                float speed = 0.1;
                vec2 flowDistort = toMouse * mouseInteraction * 1.5;

                vec2 q = vec2(fbm(st + flowDistort + vec2(0.0, uTime * speed)), fbm(st + vec2(5.2, 1.3)));
                vec2 r = vec2(fbm(st + 4.0 * q + vec2(uTime * speed)), fbm(st + 4.0 * q + vec2(5.2)));
                float f = fbm(st + 4.0 * r);

                warpSt += r * 0.1 * uIntensity;
                vec3 psychedelic = mix(uColor, uColor * 1.8, f); 
                finalColor += psychedelic * f * f * uIntensity;
            } 
            else if (uMode == 2) {
                float speed = 1.5;
                warpSt += toMouse * mouseInteraction * 0.2;

                float fire = fbm(st * 4.0 + vec2(0.0, -uTime * speed)); 
                warpSt.x += fire * 0.05 * uIntensity; 
                warpSt.y += fire * 0.08 * uIntensity;

                float heat = smoothstep(0.0, 1.0, fire);

                vec3 cRed = vec3(0.8, 0.1, 0.0);
                vec3 cOrange = vec3(1.0, 0.5, 0.0);
                vec3 cYellow = vec3(1.0, 0.9, 0.2);
                vec3 fireCol = mix(cRed, cOrange, heat);
                fireCol = mix(fireCol, cYellow, smoothstep(0.5, 1.0, heat));

                finalColor += fireCol * heat * (1.4 - vUv.y) * 0.8 * uIntensity; 
            }
            else if (uMode == 3) {
                float t = uTime * 0.3;
                vec2 q = st * vec2(1.0, 0.5); 

                float aurora = 0.0;
                for(float i = 1.0; i < 4.0; i++) {
                    float wavy = sin(q.x * 2.0 * i + t * i) * 0.3;
                    wavy += mouseInteraction * 0.2 * sin(uTime * 5.0);
                    float y = q.y - 0.3 - wavy * 0.2;
                    float band = smoothstep(0.0, 0.1, y) * smoothstep(0.6, 0.1, y);
                    float n = fbm(q * 10.0 * i + vec2(0.0, t * 2.0));
                    aurora += band * n * (1.0 / i);
                }

                warpSt += vec2(0.0, aurora) * 0.2 * uIntensity;

                vec3 colA = vec3(0.0, 1.0, 0.1); 
                vec3 colB = vec3(0.0, 0.9, 0.6); 
                vec3 finalAurora = mix(colA, colB, st.x + sin(t));

                finalColor += finalAurora * aurora * 0.6 * uIntensity;
                finalColor += uColor * mouseInteraction * 0.3;
            }
            else if (uMode == 4) {
                float speed = 0.1;
                warpSt -= toMouse * mouseInteraction * 0.3;
                vec2 q = vec2(fbm(st + speed*uTime), fbm(st + vec2(1.0)));
                float f = fbm(st + q + uTime*speed);
                warpSt += f * 0.5 * uIntensity;
                finalColor += uColor * f * 0.6 * uIntensity;
            }
            else if (uMode == 5) {
                vec2 vortexCenter = vec2(aspect, 0.0);
                vec2 toCenter = st - vortexCenter;
                float len = length(toCenter);
                float angle = atan(toCenter.y, toCenter.x);
                float twist = len * 10.0 - uTime * 2.0;
                twist += mouseInteraction * 5.0; 
                float f = sin(angle * 5.0 + twist);
                warpSt += vec2(cos(f), sin(f)) * 0.05 * uIntensity;
                finalColor += uColor * smoothstep(0.0, 1.0, f) * (1.0 - len) * 0.5 * uIntensity;
            }

            float g = grid(warpSt, 20.0); 
            vec3 gridBase = vec3(0.15); 
            vec3 gridActive = uColor * 0.8;
            vec3 finalGridCol = mix(gridBase, gridActive, uIntensity * 0.8);
            finalColor += vec3(g) * finalGridCol;

            float dist = distance(vUv, vec2(0.5));
            finalColor *= 1.0 - dist * 0.6;

            gl_FragColor = vec4(finalColor, 1.0);
        }
    `
});

const plane = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), material);
scene.add(plane);

function resize() {
	const width = window.innerWidth;
	const height = window.innerHeight;
	renderer.setSize(width, height);
	uniforms.uResolution.value.set(width, height);
}
window.addEventListener("resize", resize);
resize();

window.addEventListener("mousemove", (e) => {
	const x = e.clientX / window.innerWidth;
	const y = 1.0 - e.clientY / window.innerHeight;
	uniforms.uMouse.value.set(x, y);
});

let targetColor = new THREE.Color(0x050505);
const defaultColor = new THREE.Color(0x050505);
let targetIntensity = 0.0;

function animate(time) {
	requestAnimationFrame(animate);
	uniforms.uTime.value = time * 0.001;
	uniforms.uColor.value.lerp(targetColor, 0.04);
	uniforms.uIntensity.value +=
		(targetIntensity - uniforms.uIntensity.value) * 0.05;
	renderer.render(scene, camera);
}
requestAnimationFrame(animate);

setTimeout(() => {
	canvas.style.opacity = 1;
}, 100);

const cards = document.querySelectorAll(".app-card");
cards.forEach((card) => {
	card.addEventListener("mouseenter", () => {
		const hex = card.getAttribute("data-hex");
		const mode = parseInt(card.getAttribute("data-mode") || 0);
		if (hex) targetColor.set(hex);
		uniforms.uMode.value = mode;
		targetIntensity = 1.0;
	});
	card.addEventListener("mouseleave", () => {
		targetColor.copy(defaultColor);
		targetIntensity = 0.0;
	});
});

function shareHub() {
	const shareUrl = "https://codepen.io/Julibe/full/yyOELbR";
	const viaUser = "Julibe";

	const messages = [
		"DevDesk: The ultimate developer suite for styling, refactoring, and text magic. 🚀",
		"Create faster with DevDesk. A stunning 3D dashboard with essential dev tools. ✨",
		"Classify, Refacta, TXTLY. Your new favorite web dev utilities in one place. 🔥",
		"Web design meets WebGL. Check out the DevDesk toolkit. 💻",
		"Stop wrestling with CSS and data. Let DevDesk handle the heavy lifting. 🛠️",
		"A visual DOM builder and modular pipeline? Yes please! Check out DevDesk. 🎨"
	];

	const hashtagsList = [
		"web dev",
		"css",
		"java script",
		"three js",
		"front end",
		"creative coding",
		"ui design",
		"web gl",
		"dev tools",
		"productivity"
	];

	const text = messages[Math.floor(Math.random() * messages.length)];

	let selectedTags = hashtagsList
		.sort(() => 0.5 - Math.random())
		.slice(0, 4)
		.map((tag) => tag.replace(/\s+/g, ""));

	const urlLength = 23;
	const viaLength = 6 + viaUser.length;
	const maxChars = 280;

	while (selectedTags.length > 0) {
		const tagsLength = selectedTags.reduce((acc, tag) => acc + tag.length + 2, 0);
		const totalLength = text.length + urlLength + viaLength + tagsLength;

		if (totalLength <= maxChars) break;
		selectedTags.pop();
	}

	const hashtags = selectedTags.join(",");

	const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(
		text
	)}&url=${encodeURIComponent(shareUrl)}&hashtags=${encodeURIComponent(
		hashtags
	)}&via=${encodeURIComponent(viaUser)}`;

	window.open(twitterUrl, "_blank");
}

style.css:
@import url("https://fonts.googleapis.com/css2?family=Mulish:wght@300;400;700;800;900&display=swap");

:root {
	--none: 0;
	--xxxs: 0.01em;
	--xxs: 0.25em;
	--xs: 0.5em;
	--sm: 0.75em;
	--md: 1em;
	--lg: 1.25em;
	--xl: 1.5em;
	--xxl: 1.75em;
	--xxxl: 2em;

	--black: 0, 0, 0;
	--dark: 10, 10, 10;
	--darker-grey: 30, 30, 30;

	--white: 255, 255, 255;
	--gray: 136, 136, 136;
	--pink: 236, 72, 153;
	--orange: 255, 140, 0;
	--green: 28, 187, 58;
	--blue: 59, 130, 246;
	--purple: 189, 0, 255;

	--alpha: 0.25;
	--alpha-border: 0.08;

	--font-main: "Mulish", sans-serif;
}

::-webkit-scrollbar {
	width: var(--xs);
	background: rgb(var(--black), var(--alpha));
}

::-webkit-scrollbar-track {
	background: rgb(var(--black), var(--alpha));
}

::-webkit-scrollbar-thumb {
	background: rgb(var(--white));
	border-radius: var(--xxs);
}

::-webkit-scrollbar-thumb:hover {
	background: rgb(var(--gray));
}

* {
	margin: var(--none);
	padding: var(--none);
	box-sizing: border-box;
	font-family: var(--font-main);
	outline: none;
	-webkit-tap-highlight-color: transparent;
	&,
	&::before,
	&::after {
		user-select: none;
		transition: all 1s cubic-bezier(0.34, 1.56, 0.64, 1);
	}
}
body {
	background-color: rgb(var(--black));
	color: rgb(var(--white));
	min-height: 100vh;
	display: flex;
	flex-direction: column;
	overflow-x: hidden;
	position: relative;
	font-size: var(--md);
}

strong {
	font-weight: 900;
	color: rgb(var(--white));
}

#bg-canvas {
	position: fixed;
	inset: var(--none);
	z-index: -1;
	opacity: var(--none);
	pointer-events: none;
}

.top-left-socials {
	position: fixed;
	top: var(--xxl);
	left: var(--xxl);
	z-index: 100;
	display: flex;
	gap: var(--sm);

	@media (max-width: 600px) {
		top: var(--md);
		left: var(--md);
		gap: var(--xs);
	}

	.social-link {
		width: calc(var(--xxxl) + var(--xs));
		height: calc(var(--xxxl) + var(--xs));
		border-radius: var(--xxxl);
		background: rgba(var(--gray), var(--alpha));
		display: flex;
		align-items: center;
		justify-content: center;
		color: rgba(var(--white), var(--alpha));
		text-decoration: none;
		font-size: var(--lg);
		border: calc(var(--xxxs) * 6) solid rgba(var(--white), var(--alpha-border));
		backdrop-filter: blur(5px);

		&:hover {
			background: rgb(var(--white));
			color: rgb(var(--black));
			transform: scale(1.1);
			box-shadow: 0 0 var(--md) rgba(255, 255, 255, 0.5);
		}
	}
}

.top-right-share {
	position: fixed;
	top: var(--xxl);
	right: var(--xxl);
	z-index: 100;

	@media (max-width: 600px) {
		top: var(--md);
		right: var(--md);
	}

	.share-hub-btn {
		background: linear-gradient(90deg, rgb(var(--orange)), rgb(var(--pink)));
		border: var(--none);
		padding: var(--sm) var(--xl);
		border-radius: var(--xxxl);
		color: rgb(var(--white));
		font-weight: 800;
		cursor: pointer;
		text-transform: uppercase;
		letter-spacing: 0.05em;
		font-size: var(--sm);
		box-shadow: 0 var(--xs) var(--lg) rgba(0, 0, 0, var(--alpha));
		backdrop-filter: blur(5px);

		&:hover {
			transform: translateY(calc(var(--xxs) * -0.5));
			box-shadow: 0 var(--sm) var(--xl) rgba(var(--orange), 0.4);
		}
	}
}

header {
	text-align: center;
	padding: calc(var(--xxxl) * 3) var(--md) var(--xxl) var(--md);
	z-index: 10;

	.brand-logo {
		font-size: calc(var(--xxxl) + var(--xl));
		margin-bottom: var(--xs);
		display: flex;
		align-items: center;
		justify-content: center;
		gap: var(--xxs);
		background: linear-gradient(to right, rgb(var(--white)), rgb(var(--white)));
		-webkit-background-clip: text;
		-webkit-text-fill-color: transparent;
		text-shadow: 0 var(--md) var(--xl) rgba(0, 0, 0, 0.5);

		@media (max-width: 600px) {
			font-size: calc(var(--xxxl) + var(--xs));
			gap: var(--sm);
		}

		strong {
			font-weight: 900;
			letter-spacing: -0.05em;
		}

		.brand-icon {
			font-size: var(--md);
			color: rgb(var(--white));
			background: var(--none);
			-webkit-text-fill-color: rgb(var(--white));
			filter: drop-shadow(0 0 var(--md) rgba(var(--white), 0.3));
		}
	}

	.slogan {
		font-size: var(--xl);
		color: rgb(var(--white));
		letter-spacing: 0.05em;

		@media (max-width: 600px) {
			font-size: var(--lg);
		}

		strong {
			font-weight: 700;
			color: rgb(var(--white));
		}
	}

	p {
		margin-top: var(--sm);
		color: rgb(var(--gray));
		font-size: var(--md);

		strong {
			color: rgb(var(--white));
		}
	}
}

main.sisters-grid {
	display: grid;
	grid-template-columns: repeat(3, 1fr);
	gap: var(--xxl);
	max-width: calc(var(--xxxl) * 41);
	width: 90%;
	margin: 0 auto var(--xxxl);
	perspective: 1000px;
	z-index: 10;

	@media (max-width: 1024px) {
		grid-template-columns: repeat(2, 1fr);
	}

	@media (max-width: 768px) {
		grid-template-columns: 1fr;
		gap: var(--lg);
	}
}

.section-label {
	text-align: center;
	color: rgb(var(--white));
	font-size: var(--xl);
	letter-spacing: 0.1em;
	margin: var(--xxl) 0;
	position: relative;
	z-index: 2;

	strong {
		font-weight: 800;
		color: rgb(var(--white));
	}
}

.utils-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: var(--xxl);
	max-width: calc(var(--xxxl) * 31);
	width: 90%;
	margin: 0 auto var(--xxxl);
	z-index: 10;

	@media (max-width: 900px) {
		grid-template-columns: 1fr;
		gap: var(--lg);
	}
}

.app-card {
	--theme-color: 255, 255, 255;

	background: rgba(var(--dark), var(--alpha));
	border: calc(var(--xxxs) * 6) solid rgba(var(--white), var(--alpha-border));
	border-radius: var(--lg);
	padding: var(--xxl);
	text-decoration: none;
	color: rgb(var(--white));
	display: flex;
	flex-direction: column;
	align-items: flex-start;
	position: relative;
	overflow: hidden;
	backdrop-filter: blur(4px);
	-webkit-backdrop-filter: blur(4px);
	transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
	box-shadow: 0 var(--xs) var(--lg) rgba(0, 0, 0, var(--alpha));
	cursor: pointer;

	&.card-txtly {
		--theme-color: var(--green);
	}

	&.card-refacta {
		--theme-color: var(--orange);
	}

	&.card-classify {
		--theme-color: var(--pink);
	}

	&.card-prismatico {
		--theme-color: var(--blue);
	}

	&.card-hexli {
		--theme-color: var(--purple);
	}

	&:hover {
		transform: translateY(calc(var(--xs) * -1)) scale(1.02);
		box-shadow: 0 var(--xl) calc(var(--xxxl) * 2) rgba(0, 0, 0, var(--alpha));
		border-color: rgba(var(--white), 0.2);
		background: rgba(var(--darker-grey), 0.6);

		.icon-box {
			background: rgb(var(--theme-color));
			color: rgb(var(--black));
			box-shadow: 0 0 calc(var(--xxxl) + var(--xs)) rgb(var(--theme-color));
			border-color: transparent;
		}

		h3 strong,
		h2 strong {
			color: rgb(var(--theme-color));
		}

		.btn-launch {
			border-color: rgb(var(--theme-color));
			color: rgb(var(--theme-color));
		}
	}

	&.card-prismatico:hover .icon-box,
	&.card-hexli:hover .icon-box {
		color: rgb(var(--white));
	}

	.icon-box {
		width: calc(var(--xxxl) * 1.5);
		height: calc(var(--xxxl) * 1.5);
		border-radius: var(--md);
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: var(--xxxl);
		background: rgba(var(--gray), var(--alpha));
		border: calc(var(--xxxs) * 6) solid rgba(var(--white), var(--alpha-border));
		margin-bottom: var(--xl);
		position: relative;
		z-index: 2;
		flex-shrink: 0;
	}

	h3,
	h2 {
		font-size: var(--xxl);
		margin: var(--none) var(--none) var(--xs) var(--none);
		position: relative;
		z-index: 2;
		line-height: 1.1;

		strong {
			font-weight: 900;
		}
	}

	.slogan {
		font-size: var(--md);
		margin-bottom: var(--md);
		color: rgb(var(--white));
		letter-spacing: var(--none);
		line-height: 1.4;
		position: relative;
		z-index: 2;

		strong {
			font-weight: 700;
			color: rgb(var(--white));
		}
	}

	p {
		font-size: var(--md);
		color: rgb(var(--gray));
		line-height: 1.6;
		margin-bottom: var(--xxxl);
		position: relative;
		z-index: 2;

		&:last-of-type {
			flex-grow: 1;
		}
	}

	.btn-launch {
		margin-top: auto;
		padding: calc(var(--xs) + var(--xxxs) * 10) calc(var(--md) + var(--xxs));
		border-radius: var(--xxxl);
		font-weight: 700;
		font-size: var(--sm);
		border: calc(var(--xxxs) * 6) solid rgba(var(--white), var(--alpha-border));
		background: rgba(0, 0, 0, 0.3);
		color: rgb(var(--white));
		display: flex;
		align-items: center;
		gap: var(--xs);
		position: relative;
		z-index: 2;
		width: fit-content;
	}
}

.card-small {
	padding: var(--xxxl);
	flex-direction: row;
	align-items: flex-start;
	gap: var(--xl);

	@media (max-width: 600px) {
		padding: var(--xl);
		flex-direction: column;
	}

	.icon-box {
		margin-bottom: var(--none);
		width: calc(var(--xxxl) + var(--md));
		height: calc(var(--xxxl) + var(--md));
		font-size: var(--xl);
		margin-top: var(--xxs);

		@media (max-width: 600px) {
			margin-bottom: var(--md);
		}
	}

	.content {
		display: flex;
		flex-direction: column;
		position: relative;
		z-index: 2;
		flex: 1;
	}

	h3 {
		font-size: var(--xl);
		margin-bottom: var(--xxs);
	}

	.slogan {
		margin-bottom: var(--sm);
		font-size: var(--sm);
		opacity: var(--alpha);
	}

	p {
		font-size: var(--md);
		margin-bottom: var(--lg);
		line-height: 1.5;
	}

	.btn-launch {
		margin-top: auto;
		font-size: var(--sm);
		padding: var(--xs) var(--md);
		align-self: flex-start;
	}
}

footer {
	margin-top: auto;
	border-top: calc(var(--xxxs) * 6) solid rgba(var(--white), var(--alpha-border));
	padding: var(--xxxl);
	text-align: center;
	background: rgb(var(--black));
	position: relative;
	z-index: 10;

	p {
		color: rgb(var(--gray));
		font-size: var(--sm);
		margin-bottom: var(--none);

		strong {
			color: rgb(var(--white));
		}
	}
}
